export async function handlePayment(event: PaymentEvent) {
  const order = await db.orders.findById(event.orderId);
  if (order.status === 'paid') return;
  await db.orders.update(event.orderId, { status: 'paid' });
  await fulfillment.queue(event.orderId);
}

input.new_string:
export async function handlePayment(event: PaymentEvent) {
  const result = await db.orders.updateWhere(
    { id: event.orderId, status: { not: 'paid' } },
    { status: 'paid', paidEventId: event.id },
  );
  if (result.updatedCount === 0) return;
  await fulfillment.queue(event.orderId);
}
